mapper.update:
update campaign_mst set
    camp_nm = #{camp_nm}, surv_gb = #{surv_gb}, actdate = #{actdate}, remark = #{remark},
    status = #{status}, start_ment = #{start_ment}, end_ment = #{end_ment}, updtime = getdate(), updemp = #{updemp}
where cmpycd = #{cmpycd} and camp_no = #{camp_no}

mapper.select:
SELECT a.call_seq as call_seq, a.cmpycd as cmpycd, a.camp_no as camp_no, a.surv_gb as surv_gb, a.cust_nm as cust_nm, a.email as email, a.tel_no as tel_no, a.status as status, isnull(a.rslt_cd,'') as rslt_cd, isnull(b.codenm, '미처리') as rslt_nm, a.userid as userid, a.ext_data as ext_data, r.rslt_no as rslt_no, format(r.start_dtime, 'yyyy-MM-dd HH:mm:ss') as start_dtime, format(r.end_dtime, 'yyyy-MM-dd HH:mm:ss') as end_dtime, r.remark as remark, r.rec_file as rec_file, r.media_type as media_type, r.chat_log as chat_log, u.usernm as consultnm from campaign_call_list a left outer join haba900t_tbl b on b.cdtype = '920' and a.rslt_cd = b.codecd outer apply ( select top 1 rs.rslt_no, rs.start_dtime, rs.end_dtime, rs.remark, rs.rec_file, rs.media_type, rs.chat_log, rs.userid, rs.cmpycd from campaign_rslt_mst rs where rs.cmpycd = a.cmpycd and rs.call_seq = a.call_seq order by rs.rslt_no desc ) r left outer join haba920t_tbl u on r.userid = u.userid and r.cmpycd = u.cmpycd where a.cmpycd = #{cmpycd} and a.camp_no = #{camp_no} AND a.call_seq = #{call_seq} AND a.rslt_cd = #{filter}
and (a.cust_nm like '%' + #{keyword} + '%' or a.tel_no like '%' + #{keyword} + '%' or a.email like '%' + #{keyword} + '%')
order by a.call_seq desc

